// @hoge1e3/dom-id
export function id(pre){ 
  pre=uniq(pre||"i");
  return new Proxy(()=>pre, {
    get(target, p) {
      if(p==="toString"){
        return ()=>pre;
      }
      if (typeof p === "symbol" || p === "then" || p === "toString") {
          return Reflect.get(target, p);
      }
      //const t=args.map((a:any)=>transfers.get(a))
      return id(`${pre}-${p}`);
    },
    apply(){
      return id(`${pre}-`);
    }
  });
}
  let c=1;

function uniq(pre){
  if(!pre.endsWith("-")&&
    !document.getElementById(pre)){
    return pre;
  }
  for(let i=0;i<100000;i++){
    c++;
    const res=`${pre}${c.toString(36)}`;
    if(!document.getElementById(res)){
      return res;
    }
    /*if(Math.random()<0.5)c*=2;
    else*/
  }
}